var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그간 무탈하게 지내셨나요, 주인님.","JPN":"いかがお過ごしでしたか、ご主人様。","ENG":"I hope all is well with you, Master.","TWN":"你過得還好嗎，主人。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_18"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그라운드 원에서 있었던 사건에 대한 참고인 조사가 오늘로 마무리되었습니다.","JPN":"グラウンド・ワンでの事件に関する参考人調査が本日で終わりました。","ENG":"Today marked the last day of my interview at Ground One on the latest incident.","TWN":"對於在G1發生的事件，相關證人的調查今天已經結束了。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_19"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"맨션에 대해선 정보부 분들도 일찍부터 조사하고 계셨기에, 증언을 조건으로 선처 받을 수 있었습니다.","JPN":"マンションに関しては情報部の方もかねてから調べており、証言を条件に善処されることができました。","ENG":"It turns out the intelligence agents were already investigating the Mansion, so I received leniency in return for my testimony.","TWN":"情報部的人之前就已經開始調查曼森，作為從寬處理的條件，我答應作證。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_20"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"주인님께서도 저와 같은 풍경을 보고 계실까 궁금한 마음에, 이렇게 편지를 적어 올립니다.","JPN":"ご主人様も私と同じ風景を眺めているのか気になり、こうしてお手紙をしたためました。","ENG":"As I write this letter, I'm curious if you also see a similar scene unfold before you.","TWN":"不知道主人您是否和我看著同樣的景色，特此寫信向您問安。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_21"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"저희가 있는 도시에는 오늘 첫눈이 내렸습니다. ","JPN":"私たちの住む都市には本日初雪が降りました。 ","ENG":"It snowed for the first time this year in the city. ","TWN":"我們的城市今天下了第一場雪。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"오오! 선배님들! 조사 받느라 고생하셨슴다!","JPN":"おお、先輩方！　調査お疲れ様っす！","ENG":"Ooh, Senior Maids! I'm glad you're finally done with the investigation!","TWN":"噢噢！前輩們！你們接受調查辛苦了！"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"너 쪽팔리게 선배라고 부르지 말랬지. 왜 내가 네 선배야?","JPN":"ねえ、先輩って呼ぶのはやめてって言ったでしょう。あと、なんで私があんたの先輩なの？","ENG":"Like I said, we are not your Senior! Stop calling us that!","TWN":"跟你說了不要叫我前輩，我怎麼是你的前輩了？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"헤헤. 모네보다 일찍 메이드가 되셨으니까 그렇슴다!","JPN":"ヘヘッ、モネより先にメイドになったからっす！","ENG":"Heh heh, it's because you became a maid earlier than me, ma'am!","TWN":"嘿嘿，因為您比莫妮更早成為了女僕啊！"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"모네는 식구가 늘게 되어 무척 기쁜 듯합니다.","JPN":"モネは家族が増えたことがとても嬉しいみたいです。","ENG":"Mone seems to be very excited with the addition of new family.","TWN":"多了個家人，莫妮似乎很開心。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_22"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"리코리스는 조사 내내 마크란 분이 자기 상사라고 했는데, 그런 이름의 요원은 없다는 응답만 받았어요.","JPN":"リコリスは調査の時に、マークという方が自分の上司と言っていましたが、そのような名前の要員は存在しないという返答でした。","ENG":"During the interviews, Lycoris insisted that she was working for someone named Mark, but the agency folks kept saying there was no person by that name.","TWN":"莉克麗絲接受調查的時候說一個叫馬克的人是自己的上司，但他們說沒有那樣的人。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_23"},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"이후에는 양측 모두 사정을 감추고 싶어하는 눈치였기에 모른 척 하기로 했습니다.","JPN":"その後は双方とも事情を隠したい様子だったので、知らないふりをすることにしました。","ENG":"It seemed like both sides were trying to keep their stories discreet, so I decided to turn a blind eye to them.","TWN":"之後感覺雙方都不想提及此事，所以我也裝作不知道。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_24"},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"여기까지 나오실 필요는 없었어요. 메이드장님.","JPN":"お迎えに来てくださらなくてもいいんですよ、メイド長。","ENG":"You didn't have to come out all the way here, Chief Maid.","TWN":"你不用特意出來的，女僕長大人。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후훗. 갑자기 눈 오는 거리를 산책하고 싶어지더군요.","JPN":"ふふっ、突然雪の降る街を散歩したくなりました。","ENG":"Hah hah, I just wanted to go for a stroll in the snow.","TWN":"呼呼，我只是突然想在雪地裡散步而已。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"수첩이 그새 많이 닳았네요. 가는 길에 하나 더 사야겠어요.","JPN":"手帳がかなり古くなってしまいましたね。一冊買って帰りましょうか。","ENG":"Your notepad has worn out a lot. Let's get you a new one on the way back.","TWN":"手冊都這麼破了，路上買個新的吧。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"아, 그건......","JPN":"ああ、それは……","ENG":"Oh, erm...","TWN":"啊，這是……"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......땡큐베리감사, 입니다.","JPN":"……あざっすベリーサンキュー、です。","ENG":"TYSM, if that's how they say it.","TWN":"……非常感謝。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"릴리는 어린 시절부터 맨션에 지냈기 때문에, 사회에 대해서는 많이 모르는 편입니다.","JPN":"リリーは子どもの頃からマンションで暮らしていたので、まだ社会について知らないことが多いです。","ENG":"Since Lily spent most of her childhood at the Mansion, she has much to learn about how the rest of society functions.","TWN":"莉莉從小生活在曼森，可以說對社會是一無所知。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_25"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 어린 나이에 스스로 세상에 대해 배우려고 하는 모습이 무척 장해서, 저도 항상 응원해 주고 있습니다.","JPN":"ですがまだ幼いにも関わらず、みずから世間を学ぼうとする姿勢が健気で、私も応援することにしました。","ENG":"Still, I'm so proud of her for trying to learn more about the world at such a young age. I'm always rooting for her.","TWN":"即便如此，小小年紀的她卻還是很認真的學習這個世界，真的非常了不起，我也一直支持她。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_26"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"이번에는, 좀 더 솔직한 방법으로요.","JPN":"今度こそ、もっと素直に見守ってあげたいと思います。","ENG":"And this time, I'll make sure she realizes that, too.","TWN":"當然，這次是用一些更坦蕩的辦法。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_27"},{"id":"L35_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"날씨가 많이 춥습니다. 목도리를 가져 왔으니까 다들 목에 두르도록 하세요.","JPN":"今日は寒いですね。マフラーを持ってきたのでみんなしっかり巻いてくださいね。","ENG":"It's very cold today. I brought scarves for each of you, so please put them on.","TWN":"天氣變冷了，我帶了圍巾，大家都圍上吧。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"우와~ 무지 따뜻하지 말임다~","JPN":"わぁ～めちゃくちゃあったかいっす～！","ENG":"Wow, it's super warm, ma'am!","TWN":"哇～真的好暖和啊～"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"크흠. 매번 말하는데 난 정보부가 감시해야 된다니까 별 수 없이 여기 들어온 거야.","JPN":"ごほん。言っておくけど私は情報部から監視が必要って言われて仕方なくあなたたちに付き合っているんだからね。","ENG":"Ahem, like I said, I'm only still here because the agency said I've got to keep an eye on you.","TWN":"咳咳，我是因為情報部說要監視我，所以才不得已來到這裡的。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"목도리 하나 받았다고 좋아라 할 줄 알았다면 오산이라고.","JPN":"マフラー一枚で喜ぶと思ったら大間違いよ。","ENG":"Didn't think you I'd get all excited about this scarf.","TWN":"別以為送個圍巾，我就會很開心。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"안 그래, 릴리?","JPN":"そうでしょ、リリー？","ENG":"Isn't that right, Lily?","TWN":"是不是，莉莉？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......물론입니다. 메이드는 늘 감정을 갈무리할 줄 알아야죠.","JPN":"……もちろんです。メイドは常に感情をコントロールする必要があります。","ENG":"Of course. A maid should always know how to keep her feelings under control.","TWN":"……當然，女僕要懂得隱藏自己的感情。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"맨션은 사라졌다고 합니다.","JPN":"マンションは消えたそうです。","ENG":"The Mansion is said to be gone.","TWN":"聽說曼森消失了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_28"},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"제가 기억하던 장소에는 텅 빈 저택만 남아 있었다고 하더군요.","JPN":"私が覚えていた場所は空っぽになった邸宅だけが残っていたそうです。","ENG":"They said there was only an empty house left in the place I remembered.","TWN":"在我記憶中的那個地方，如今只剩下一個空蕩蕩的房子。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_29"},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"마스터 역시 체포 이후 며칠 지나지 않아 실종되었다고 합니다.","JPN":"マスターも逮捕されてから数日後に失踪したようです。","ENG":"The Master also went missing a few days after her arrest.","TWN":"曼森的主人被抓之後，沒過多久就失蹤了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_30"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"항간에는 정보부에서 준비한 특별 감옥으로 이송되었다는 말도 있습니다만......","JPN":"噂では情報部が用意した特別監獄に移送されたという話もありますが……","ENG":"Some say that the intelligence authorities transferred her to a special supermax prison...","TWN":"坊間傳聞說，她被移送到了情報部特設的監獄……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_31"},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"아마, 그녀가 지닌 특별한 힘으로 탈출했을 테죠.","JPN":"おそらく、彼女が持つ特別な力で脱出したのでしょう。","ENG":"But I'm sure she escaped with her unique powers.","TWN":"但我想，她應該是用她那特殊的力量逃脫了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_32"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"제가 아는 그 사람은 순순히 포기할 성격이 아니니까요.","JPN":"私の知っているあの人は、素直にあきらめる性格ではありませんので。","ENG":"As far as I know, she's not the type to give up so easily.","TWN":"因為我認識的她，是一個不會輕易放棄的人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_33"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"언젠가는 그녀와 다시 마주하게 될 날이 오겠죠.","JPN":"いつかは彼女とまた向き合う日が来るでしょう。","ENG":"Someday, I'm sure I'll have to face her again.","TWN":"總有一天我會跟她重新相遇吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_34"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 그 날이 오기 전까지는......","JPN":"でも、その日が来るまでは……","ENG":"But until that day...","TWN":"在那一天到來之前……"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_35"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"제게는 과분한 이 평온 속에서, 지난 날 저질렀던 잘못들을 속죄하려 합니다.","JPN":"私には過分なこの平穏の中で、過去の過ちを償いたいと思います。","ENG":"I will try to atone for my sins throughout these undeserved days of peace.","TWN":"我要在這個過分的平靜中，為我過去犯下的錯誤贖罪。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_36"},{"id":"L10_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"오오! 리코리스 선배! 저기 진열대에 김이 모락모락 풍기는 핫도그 어떠심까!","JPN":"おお！　リコリス先輩！　あそこにある出来立てほやほやのホットドッグはどうっすか？","ENG":"Ooo, Lycoris! Look at those steaming hot dogs on rollers! Don't they look delicious?","TWN":"噢噢！莉克麗絲前輩！那個熱氣騰騰的熱狗怎麼樣！"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야. 핫도그쯤은 내가 만들어 줘도 되잖아.","JPN":"ちょっと。ホットドッグなら私が作ってあげるわよ？","ENG":"Come on, I could make you a hot dog.","TWN":"喂，我也可以做熱狗給你的。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으엑. 모네는 핫도그만 봐도 속이 쓰리기 싫슴다.","JPN":"うわあ。モネは先輩のホットドッグを見るだけで胃が痛くなるからイヤっす。","ENG":"Blech... Mone doesn't want a HOT dog.","TWN":"額，莫妮可不想吃完熱狗就開始胃疼。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐?! 야, 너 이리 와 봐!","JPN":"えっ！？　ちょっとこっちに来なさいよ！","ENG":"What? Hey, come here for a sec!","TWN":"什麼？！喂，你過來！"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"왜 그러나요, 릴리?","JPN":"どうしましたか、リリー？","ENG":"What's wrong, Lily?","TWN":"怎麼了，莉莉？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"고민이 있다면 얘기해 주세요. 함께 생각해 보죠.","JPN":"悩みがあるなら話してくれませんか。一緒に考えてみましょう。","ENG":"If there's something troubling you, let's talk about it.","TWN":"你有什麼煩惱就說出來吧。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"아무것도 아닙니다.","JPN":"何でもありません。","ENG":"It's nothing.","TWN":"沒什麼。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그저...... 저는 아직 메이드장님이 말씀하신 새로운 주인님을 만나 뵙지 못했으니까요.","JPN":"ただ……私はまだメイド長が話してくれた新しいご主人様にお会いしていません。","ENG":"It's just that... I still haven't met the new master you spoke of.","TWN":"只是……我到現在都還沒見到女僕長大人您說的新主人。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이제 조사도 끝났으니, 만나 뵈러 갈 수 있지 않나요?","JPN":"もう調査も終わりましたし、会いに行けるのではありませんか？","ENG":"Could we go see him, now that the investigation is over?","TWN":"現在調查也結束了，是不是可以去見他了？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님은 여러모로 바쁜 분이세요. 언제나 저희들만 챙겨 주실 수는 없답니다.","JPN":"ご主人様は何かと忙しい方です。常に私たちだけに気を遣うことはできません。","ENG":"The new Master is quite busy, in many ways. We can't expect him to take care of us exclusively.","TWN":"主人他很忙，總不能一直讓他為我們操心。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만......","JPN":"ですが……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"다녀오라고 하셨던 말씀, 기억하고 있습니다.","JPN":"私の帰りを待っているとおっしゃってくれたこと、覚えております。","ENG":"I still remember how you told me I could return to you.","TWN":"我還記得您跟我說過，您會等我回來。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_37"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"부족한 힘이나마 주인님의 일에 보탬이 될 수 있다면, 언제든 플로라 메이드 서비스를 찾아 주시길.","JPN":"微力ではございますが、ご主人様のお仕事の助けになれるなら、いつでもフローラメイドサービスをお訪ねくださいませ。","ENG":"Please seek out the Flora Maid Service anytime, if we may assist you in any way.","TWN":"雖然我還有很多不足的地方，但如果能幫到您，歡迎您隨時找芙蘿拉女僕服務。"},"stage":{"bg":"BLACK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_38"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼, 부름을 기다리고 있겠습니다. 주인님.","JPN":"それでは、ご主人様のお呼びをお待ちしております。","ENG":"I look forward to hearing from you, Master.","TWN":"我隨時等候您的吩咐，主人。"},"stage":{"bg":"SS_MAID_04","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_MAID_S_LEADER_TRAILER_39"}]`);export{e as default};